mapper.select:
SELECT id, student_id, paper_id, start_time, submit_time, total_score, status, create_time
FROM exam_system.exam_record
WHERE student_id = #{studentId}
  AND paper_id = #{paperId}

SELECT id, student_id, paper_id, start_time, submit_time, total_score, status, create_time
FROM exam_system.exam_record
WHERE id = #{examId}

mapper.insert:
INSERT INTO exam_system.answer_record (
    exam_id, question_id, question_title_snapshot, option_snapshot, student_answer,
    correct_answer_snapshot, is_correct, score, create_time
) VALUES (
    #{examId}, #{questionId}, #{questionTitleSnapshot}, #{optionSnapshot}, #{studentAnswer},
    #{correctAnswerSnapshot}, #{isCorrect}, #{score}, #{createTime}
)

INSERT INTO exam_system.wrong_question (
    student_id, question_id, exam_id, student_answer, correct_answer, create_time
) VALUES (
    #{studentId}, #{questionId}, #{examId}, #{studentAnswer}, #{correctAnswer}, #{createTime}
)

mapper.select:
SELECT exam_id, student_id, student_name, paper_id, paper_name,
       total_score, pass_score, submit_time, is_pass
FROM exam_system.v_student_score
WHERE exam_id = #{examId}
  AND student_id = #{studentId}
